function dateInRange(c,fromId,toId){let from=val(fromId),to=val(toId),d=c.noticeDate;if(from&&d<from)return false;if(to&&d>to)return false;return true}
function tab(id,btn){activeView=id;document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById(id).classList.add('active');document.querySelectorAll('.tabs button').forEach(b=>b.classList.remove('active'));btn.classList.add('active');if(id!=='intake')cancelEdit(false);render()}function startNewCase(btn){cancelEdit(false);resetNewCaseForm();tab('intake',btn)}function setTabByIndex(i,id){activeView=id;document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById(id).classList.add('active');document.querySelectorAll('.tabs button').forEach(b=>b.classList.remove('active'));document.querySelectorAll('.tabs button')[i].classList.add('active');render()}function setQueueFilter(f){queueFilter=f;render()}function setDashboardFilter(field,value){dashboardFilters[field]=value.toLowerCase().trim();renderDashboard()}function setAuditFilter(field,value){auditFilters[field]=value.toLowerCase().trim();renderAudit()}function setLedgerFilter(field,value){ledgerFilters[field]=value.toLowerCase().trim();renderLedger()}function setManagerFilter(field,value){managerFilters[field]=value.toLowerCase().trim();renderManager()}function setQueueSort(field,value){queueSort[field]=value;renderCaseList()}function setDashboardSort(field,value){dashboardSort[field]=value;renderDashboard()}function setAuditSort(field,value){auditSort[field]=value;renderAudit()}function setManagerSort(field,value){managerSort[field]=value;renderManager()}function setLedgerSort(field,value){ledgerSort[field]=value;renderLedger()}function toggleSort(sortObj,field,renderFn){if(sortObj.field===field){sortObj.direction=sortObj.direction==='asc'?'desc':'asc'}else{sortObj.field=field;sortObj.direction='desc'}renderFn()}function sortArrow(sortObj,field){return sortObj.field===field?(sortObj.direction==='asc'?'&#9650;':'&#9660;'):'&#8597;'}function toggleDashboardSort(field){toggleSort(dashboardSort,field,renderDashboard)}function toggleAuditSort(field){toggleSort(auditSort,field,renderAudit)}function toggleManagerSort(field){toggleSort(managerSort,field,renderManager)}function toggleLedgerSort(field){toggleSort(ledgerSort,field,renderLedger)}function sortValue(v){let t=Date.parse(v);return isNaN(t)?String(v||'').toLowerCase():t}function applySort(list,sort,getter){let dir=sort.direction==='asc'?1:-1;return list.slice().sort((a,b)=>{let av=sortValue(getter(a,sort.field)),bv=sortValue(getter(b,sort.field));return av>bv?dir:av<bv?-dir:0})}
function caseTxnType(c){let txns=getFlaggedTransactions(c);return (txns[0]&&txns[0].type)||c.txnType||''}function caseClaimType(c){return c.claimType||''}function matchesQueueDropdowns(c){let t=val('queueTxnTypeFilter'),e=val('queueClaimTypeFilter');return (!t||caseTxnType(c)===t)&&(!e||caseClaimType(c)===e)}function matchesRegE(c){let r=classify(c).likelyRegE;if(queueFilter==='regE')return r;if(queueFilter==='nonRegE')return !r;return true}function isManagerCase(c){return (c.status.includes('Final')||c.managerReviewed)&&!c.auditReady}function isAuditCase(c){return c.auditReady}function isNormalReviewCase(c){return !c.auditReady}function visibleQueueCases(){let base=cases;if(activeView==='dashboard')return [];if(activeView==='manager')base=cases.filter(isManagerCase);else if(activeView==='audit'||activeView==='auditDetailView')base=cases.filter(isAuditCase);else if(activeView==='ledger')base=cases.filter(c=>ledgerCreditTotal(c)>0);else base=cases.filter(isNormalReviewCase).filter(matchesRegE);let rows=base.filter(c=>dateInRange(c,'queueDateFrom','queueDateTo')).filter(matchesQueueDropdowns);return applySort(rows,{field:'noticeDate',direction:'desc'},(c,f)=>c.noticeDate)}function queueAction(c){if(activeView==='manager')return `selectCase('${c.id}');setTabByIndex(2,'manager')`;if(activeView==='audit')return `openAuditCase('${c.id}')`;if(activeView==='ledger')return `openProvisionalAdjustment('${c.id}')`;return `selectCase('${c.id}')`}
function matchesDashboard(c){let calc=classify(c);let v={caseId:c.id,source:c.source,customer:c.customer,account:c.account,status:c.status+' '+(calc.likelyRegE?'Reg E':'Non Reg E'),txnType:caseTxnType(c),claimType:caseClaimType(c)};return Object.entries(dashboardFilters).every(([k,f])=>!f||String(v[k]||'').toLowerCase().includes(f))&&dateInRange(c,'dashboardDateFrom','dashboardDateTo')}
function matchesAudit(c){let calc=classify(c);let v={caseId:c.id,source:c.source,customer:c.customer,account:c.account,status:c.status+' '+(calc.likelyRegE?'Reg E':'Non Reg E'),txnType:caseTxnType(c),claimType:caseClaimType(c)};return Object.entries(auditFilters).every(([k,f])=>!f||String(v[k]||'').toLowerCase().includes(f))}function matchesLedgerRow(r){let v={caseId:r.caseId,customer:r.customer,account:r.account,amount:String(r.entry.amount)+' '+money(r.entry.amount)};return Object.entries(ledgerFilters).every(([k,f])=>!f||String(v[k]||'').toLowerCase().includes(f))}function matchesManager(c){let v={caseId:c.id,customer:c.customer,account:c.account,amount:String(c.amount)+' '+money(c.amount),status:c.status+' '+(c.finalDecision||'')+' '+c.creditStatus};return Object.entries(managerFilters).every(([k,f])=>!f||String(v[k]||'').toLowerCase().includes(f))}
function addCalendarDaysOnly(dateStr,days){let d=new Date(dateStr+'T12:00:00');d.setDate(d.getDate()+days);return d.toISOString().slice(0,10)}function transactionListHtml(c,title='Claim Transactions'){let txns=getFlaggedTransactions(c);return '<h3>'+title+'</h3><table><tr><th>#</th><th>Date</th><th>Type</th><th>Merchant / Recipient</th><th>Amount</th></tr>'+txns.map((t,i)=>'<tr class="txFlag"><td>'+(i+1)+'</td><td>'+t.date+'</td><td>'+t.type+'</td><td>'+t.merchant+'</td><td>'+money(t.amount)+'</td></tr>').join('')+'</table>'}
function transactionTypeOptions(selected){let opts=['Zelle / P2P','ACH Debit','Debit Card POS','ATM Withdrawal','Online Banking Transfer','Wire Transfer','Check','Credit Card'];return opts.map(o=>'<option '+(o===selected?'selected':'')+'>'+o+'</option>').join('')}
function defaultTransaction(){return{date:'2026-06-20',type:'Zelle / P2P',merchant:'Unknown Zelle Recipient',amount:450,primary:true}}
