function buildFlaggedTransactions(){let rows=readTransactionRows();return rows.length?rows:[defaultTransaction()]}
function flaggedTransactionsHtml(c){let txns=getFlaggedTransactions(c);let total=transactionTotal(txns);return '<h3>Flagged Transactions In This Claim</h3><p class="muted">This claim includes '+txns.length+' disputed transaction(s). Total flagged amount: <strong>'+money(total)+'</strong></p><table><tr><th>Date</th><th>Type</th><th>Merchant / Recipient</th><th>Amount</th><th>Role</th></tr>'+txns.map(t=>'<tr class="txFlag"><td>'+t.date+'</td><td>'+t.type+'</td><td>'+t.merchant+'</td><td>'+money(t.amount)+'</td><td>'+(t.primary?'Primary':'Additional')+'</td></tr>').join('')+'</table>'}
function simulatedAccountHistory(c){let flagged=getFlaggedTransactions(c).map(t=>({...t,flagged:true}));let normal=[{date:'2026-06-23',type:'Debit Card POS',merchant:'Publix #1442',amount:-86.43},{date:'2026-06-22',type:'ACH Credit',merchant:'Payroll Deposit',amount:2450.00},{date:'2026-06-19',type:'ATM Withdrawal',merchant:'ATM Hialeah',amount:-100.00},{date:'2026-06-17',type:'Debit Card POS',merchant:'Shell Miami',amount:-42.10},{date:'2026-06-15',type:'Online Banking Transfer',merchant:'Transfer to Savings',amount:-250.00}];return[...flagged.map(t=>({date:t.date,type:t.type,merchant:t.merchant,amount:-Math.abs(Number(t.amount||0)),flagged:true})),...normal].sort((a,b)=>String(b.date).localeCompare(String(a.date)))}
function openCaseTool(title,subtitle,html){activeView='review';document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById('caseTool').classList.add('active');document.querySelectorAll('.tabs button').forEach(b=>b.classList.remove('active'));document.querySelectorAll('.tabs button')[1].classList.add('active');document.getElementById('caseToolTitle').textContent=title;document.getElementById('caseToolSub').textContent=subtitle||'';document.getElementById('caseToolBody').innerHTML=html;renderCaseList()}function backToCaseReview(){showHistoryId=null;showCreditPanelId=null;setTabByIndex(1,'review')}function accountHistoryHtml(c){let rows=simulatedAccountHistory(c);return '<div class="notice">Demo account history for '+c.account+'. Flagged claim transactions are highlighted.</div><table><tr><th>Date</th><th>Type</th><th>Description</th><th>Amount</th><th>Flag</th></tr>'+rows.map(r=>'<tr class="'+(r.flagged?'txFlag':'')+'"><td>'+r.date+'</td><td>'+r.type+'</td><td>'+r.merchant+'</td><td>'+money(r.amount)+'</td><td>'+(r.flagged?'Claim transaction':'-')+'</td></tr>').join('')+'</table>'}
function toggleAccountHistory(){let c=cur();if(!c)return;openCaseTool('Account Transaction History','Review account activity for '+c.id+' - '+c.customer,accountHistoryHtml(c))}
function formData(){let txns=buildFlaggedTransactions();let first=txns[0]||defaultTransaction();let temp={source:val('source'),intakeOfficer:val('intakeOfficer'),customer:val('customer'),account:val('account'),txnType:first.type,claimType:val('claimType'),merchant:first.merchant,amount:transactionTotal(txns),txnDate:first.date,noticeDate:val('noticeDate'),openedDate:val('noticeDate'),accountAge:val('accountAge'),foreign:val('foreign'),deviceStatus:val('deviceStatus'),prior:Number(val('prior')),statement:val('statement'),flaggedTransactions:txns,manualRegEStatus:val('manualRegEStatus')||'Auto',manualInitialDays:val('manualInitialDays')||'Auto',manualExtendedDays:val('manualExtendedDays')||'Auto',manualRoute:val('manualRoute')||'Auto',manualOverrideNote:val('manualOverrideNote')||''};let calc=classify(temp);let prefix=calc.likelyRegE?'REG-E':'NON-E';return{...temp,id:prefix+'-'+new Date().toISOString().slice(2,10).replaceAll('-','')+'-'+Math.floor(1000+Math.random()*9000),status:'Officer Review Needed',officerDecision:null,officerComment:'',provisional:false,creditStatus:'No credit posted',finalDecision:null,managerReviewed:false,auditReady:false,comments:[],events:[eventObj('Case created from '+val('source'))]}}
function createCase(e){e.preventDefault();if(editCaseId){updateExistingCase();return}let c=formData();let calc=classify(c);retagCaseId(c);if(calc.mixedRails&&(!c.manualRegEStatus||c.manualRegEStatus==='Auto')){alert('This claim mixes Reg E and Non Reg E transaction types. Because one claim can only use one transaction type, change the transaction type or create separate claims.');return;}c.events.push(eventObj('Machine recommendation: '+calc.route+', risk '+calc.score+', due '+calc.due10));c.events.push(eventObj('Claim contains '+getFlaggedTransactions(c).length+' flagged transaction(s), total '+money(c.amount)));autoNotify(c,'Claim received and queued for officer review.');cases.unshift(c);selectedId=c.id;render();setTabByIndex(1,'review')}
function liveCalc(){updateTransactionTotal();let txns=buildFlaggedTransactions();let first=txns[0]||defaultTransaction();let x={source:val('source'),txnType:first.type,claimType:val('claimType'),amount:transactionTotal(txns),txnDate:first.date,noticeDate:val('noticeDate'),accountAge:val('accountAge'),foreign:val('foreign'),deviceStatus:val('deviceStatus'),prior:Number(val('prior')),flaggedTransactions:txns,manualRegEStatus:val('manualRegEStatus')||'Auto',manualInitialDays:val('manualInitialDays')||'Auto',manualExtendedDays:val('manualExtendedDays')||'Auto',manualRoute:val('manualRoute')||'Auto',};let c=classify(x);let box=document.getElementById('liveResult');if(box)box.textContent='Likely Reg E: '+(c.likelyRegE?'YES':'NO')+'\nRecommended route: '+c.route+'\nNotice date: '+x.noticeDate+'\nOpened date: '+c.openedDate+'\nProvisional credit deadline: '+c.provisionalCreditDate+' ('+c.initialDays+' business days)'+'\nFinal case deadline: '+c.deadlineDate+' ('+c.extendedDays+' calendar days, maximum allowed)\nTotal claim amount: '+money(transactionTotal(txns))+'\nRisk score: '+c.score+'/100 - '+c.level+'\nCredit recommendation: '+c.creditRecommendation+'\n\nSuggested tasks:\n- '+c.tasks.join('\n- ')+'\n\nReasoning:\n- '+c.reason.join('\n- ')}
function selectCase(id){let c=cases.find(x=>x.id===id);if(c&&c.auditReady){openAuditCase(id);return}selectedId=id;setTabByIndex(1,'review')}function openAuditCase(id){selectedAuditId=id;selectedId=id;activeView='auditDetailView';document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById('auditDetailView').classList.add('active');document.querySelectorAll('.tabs button').forEach(b=>b.classList.remove('active'));document.querySelectorAll('.tabs button')[3].classList.add('active');render()}
function render(){save();let side=document.getElementById('sideQueue');let wrap=document.querySelector('.wrap');if(side){side.style.display=activeView==='dashboard'?'none':''}if(wrap){wrap.style.gridTemplateColumns=activeView==='dashboard'?'1fr':''}document.getElementById('qAll').classList.toggle('active',queueFilter==='all');document.getElementById('qRegE').classList.toggle('active',queueFilter==='regE');document.getElementById('qNonRegE').classList.toggle('active',queueFilter==='nonRegE');document.getElementById('queueRegEControls').style.display=(activeView==='manager'||activeView==='audit'||activeView==='auditDetailView'||activeView==='ledger'||activeView==='dashboard')?'none':'flex';document.getElementById('queueModeLabel').textContent=activeView==='dashboard'?'Dashboard View':activeView==='manager'?'Manager Review Cases':(activeView==='audit'||activeView==='auditDetailView')?'Audit Log Cases':activeView==='ledger'?'Cases With Provisional Credit':(queueFilter==='regE'?'Reg E Cases':queueFilter==='nonRegE'?'Non Reg E Cases':'All Cases');renderCaseList();renderDashboard();renderReview();renderLedger();renderManager();renderAudit();renderAuditDetail();liveCalc()}
function renderCaseList(){let list=visibleQueueCases();document.getElementById('caseList').innerHTML=list.map(c=>{let calc=classify(c);return '<div class="case '+(c.id===selectedId?'active':'')+'" onclick="'+queueAction(c)+'"><div class="between"><strong>'+c.id+'</strong>'+badge(c)+'</div><div>'+c.customer+'</div><div class="muted">'+c.source+' - '+c.account+' - '+c.txnType+' - '+money(c.amount)+'</div><div class="muted">Notice: '+c.noticeDate+' - '+(calc.likelyRegE?'Reg E':'Non Reg E')+' - Risk '+calc.score+'</div></div>'}).join('')||'<div class="pad muted">No cases match this queue/date filter.</div>'}
function renderDashboard(){document.getElementById('kOpen').textContent=cases.filter(c=>!c.status.includes('Final')&&!c.auditReady).length;document.getElementById('kOfficer').textContent=cases.filter(c=>c.status==='Officer Review Needed').length;document.getElementById('kManager').textContent=cases.filter(c=>isManagerCase(c)&&!c.managerReviewed).length;document.getElementById('kAudit').textContent=cases.filter(c=>c.auditReady).length;let rows=applySort(cases.filter(c=>!c.auditReady).filter(matchesDashboard),dashboardSort,(c,f)=>f==='caseId'?c.id:c.noticeDate);document.getElementById('workbench').innerHTML='<tr><th>Case<button class="sortBtn" onclick="toggleDashboardSort(\'caseId\')">'+sortArrow(dashboardSort,'caseId')+'</button><input class="filterInput" placeholder="Search case #" value="'+dashboardFilters.caseId+'" oninput="setDashboardFilter(\'caseId\',this.value)"></th><th>Source<input class="filterInput" placeholder="Search source" value="'+dashboardFilters.source+'" oninput="setDashboardFilter(\'source\',this.value)"></th><th>Customer<input class="filterInput" placeholder="Search customer" value="'+dashboardFilters.customer+'" oninput="setDashboardFilter(\'customer\',this.value)"></th><th>Account Number<input class="filterInput" placeholder="Search account" value="'+dashboardFilters.account+'" oninput="setDashboardFilter(\'account\',this.value)"></th><th>Case Type</th><th>Error Type</th><th>Status<input class="filterInput" placeholder="Search status" value="'+dashboardFilters.status+'" oninput="setDashboardFilter(\'status\',this.value)"></th><th>Risk</th><th>Notice Date<button class="sortBtn" onclick="toggleDashboardSort(\'noticeDate\')">'+sortArrow(dashboardSort,'noticeDate')+'</button></th><th>Deadline</th></tr>'+(rows.map(c=>{let calc=classify(c);return '<tr style="cursor:pointer" title="Open case" onclick="selectCase(\''+c.id+'\')"><td>'+c.id+'</td><td>'+c.source+'</td><td>'+c.customer+'</td><td>'+c.account+'</td><td>'+caseTxnType(c)+'</td><td>'+caseClaimType(c)+'</td><td>'+badge(c)+'<div class="muted mini">'+(calc.likelyRegE?'Reg E':'Non Reg E')+'</div></td><td><div class="risk"><span style="width:'+calc.score+'%"></span></div><span class="muted">'+calc.score+' '+calc.level+'</span></td><td>'+c.noticeDate+'</td><td>'+calc.deadlineDate+'</td></tr>'}).join('')||'<tr><td colspan="10">No dashboard results match your search/date filters.</td></tr>')}
function renderSteps(c){let steps=['Intake','Officer Review','Investigation','Provisional Credit','Final Decision','Manager Review','Audit Ready'];let idx=0;if(c.status==='Officer Review Needed')idx=1;if(c.status==='Investigation Open'||c.status==='Ready for Final Decision')idx=2;if(c.provisional)idx=3;if(c.status.includes('Final'))idx=4;if(c.managerReviewed)idx=5;if(c.auditReady)idx=6;return '<div class="stepper">'+steps.map((s,i)=>'<div class="step '+(i<idx?'done':i===idx?'current':'')+'">'+s+'</div>').join('')+'</div>'}
function verifyManagerCode(reason){let code=prompt(reason+'\n\nEnter manager override code:');if(code===null)return false;if(code!==MANAGER_CODE){alert('Incorrect manager code. Demo code is MANAGER123.');return false}return true}
function canModifyCase(c,action){if(!c.auditReady)return true;return verifyManagerCode('This case is marked Audit Ready and locked. '+action+' requires manager override.')}
function loadCaseIntoForm(c){document.getElementById('source').value=c.source;document.getElementById('intakeOfficer').value=c.intakeOfficer||'S. Sanz';document.getElementById('customer').value=c.customer;document.getElementById('account').value=c.account;document.getElementById('claimType').value=c.claimType;document.getElementById('noticeDate').value=c.noticeDate;document.getElementById('accountAge').value=c.accountAge;document.getElementById('foreign').value=c.foreign;document.getElementById('deviceStatus').value=c.deviceStatus;document.getElementById('prior').value=c.prior;document.getElementById('statement').value=c.statement;renderTransactionRows(getFlaggedTransactions(c));setManualControls(c);liveCalc()}
function startEditCase(){let c=cur();if(!c)return;if(!canModifyCase(c,'Editing'))return;editCaseId=c.id;loadCaseIntoForm(c);activeView='intake';document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById('intake').classList.add('active');document.querySelectorAll('.tabs button').forEach(b=>b.classList.remove('active'));document.querySelector('.plusTab').classList.add('active');document.getElementById('intakeTitle').textContent='Edit Case';document.getElementById('editBanner').style.display='block';document.getElementById('editBanner').textContent='Editing '+c.id+(c.auditReady?' - Audit override mode used.':'');document.getElementById('caseSubmitBtn').textContent='Save Case Changes';document.getElementById('cancelEditBtn').style.display='inline-block';render()}
function cancelEdit(shouldRender=true){editCaseId=null;overrideMode=false;let title=document.getElementById('intakeTitle');if(title)title.textContent='Create New Case';let banner=document.getElementById('editBanner');if(banner){banner.style.display='none';banner.textContent=''}let btn=document.getElementById('caseSubmitBtn');if(btn)btn.textContent='Create Case & Send to Officer Review';let cancel=document.getElementById('cancelEditBtn');if(cancel)cancel.style.display='none';setManualControls(null);if(shouldRender)render()}
function updateExistingCase(){let c=cases.find(x=>x.id===editCaseId);if(!c)return;let wasAudit=c.auditReady;let data=formData();let calcData=classify(data);if(calcData.mixedRails&&(!overrideMode||data.manualRegEStatus==='Auto')){alert('This claim mixes Reg E and Non Reg E transaction types. Use officer override classification or split into separate claims.');return;}Object.assign(c,{source:data.source,intakeOfficer:data.intakeOfficer,customer:data.customer,account:data.account,txnType:data.txnType,claimType:data.claimType,merchant:data.merchant,amount:data.amount,txnDate:data.txnDate,noticeDate:data.noticeDate,openedDate:data.openedDate||data.noticeDate,accountAge:data.accountAge,foreign:data.foreign,deviceStatus:data.deviceStatus,prior:data.prior,statement:data.statement,flaggedTransactions:data.flaggedTransactions,manualRegEStatus:data.manualRegEStatus,manualInitialDays:data.manualInitialDays,manualExtendedDays:data.manualExtendedDays,manualRoute:data.manualRoute,manualOverrideNote:data.manualOverrideNote});if(overrideMode){c.officerDecision='Officer override / manual mode';c.officerComment=data.manualOverrideNote||'Manual override saved.';c.status='Investigation Open';autoNotify(c,'Your claim is being reviewed after officer manual review.')}c.amount=transactionTotal(getFlaggedTransactions(c));let recalced=classify(c);c.events.push(eventObj('Derived Reg E dates refreshed: notice '+c.noticeDate+', opened '+recalced.openedDate+', provisional credit '+recalced.provisionalCreditDate+', deadline '+recalced.deadlineDate));retagCaseId(c);c.events.push(eventObj(wasAudit?'AUDIT OVERRIDE: Case edited with manager code':(overrideMode?'Officer manual override saved':'Case edited')));selectedId=c.id;cancelEdit(false);render();if(wasAudit){openAuditCase(c.id)}else{setTabByIndex(1,'review')}}
function deleteCase(){let c=cur();if(!c)return;if(!canModifyCase(c,'Deleting'))return;if(!confirm('Delete case '+c.id+'? This removes it from this demo database.'))return;let idx=cases.findIndex(x=>x.id===c.id);if(idx>=0)cases.splice(idx,1);selectedId=cases[0]?.id||null;if(selectedAuditId===c.id)selectedAuditId=null;render();if(selectedId)setTabByIndex(0,'dashboard')}
function setManualControls(c){let show=overrideMode||(c&&(c.manualRegEStatus&&c.manualRegEStatus!=='Auto'||c.manualInitialDays&&c.manualInitialDays!=='Auto'||c.manualExtendedDays&&c.manualExtendedDays!=='Auto'||c.manualRoute&&c.manualRoute!=='Auto'));let box=document.getElementById('manualOverrideBox');if(box)box.style.display=show?'block':'none';let mr=document.getElementById('manualRegEStatus');if(mr)mr.value=c?.manualRegEStatus||'Auto';let mi=document.getElementById('manualInitialDays');if(mi)mi.value=c?.manualInitialDays||'Auto';let me=document.getElementById('manualExtendedDays');if(me)me.value=c?.manualExtendedDays||'Auto';let route=document.getElementById('manualRoute');if(route)route.value=c?.manualRoute||'Auto';let note=document.getElementById('manualOverrideNote');if(note)note.value=c?.manualOverrideNote||''}
function startManualOverride(){let c=cur();if(!c)return;overrideMode=true;editCaseId=c.id;loadCaseIntoForm(c);activeView='intake';document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById('intake').classList.add('active');document.querySelectorAll('.tabs button').forEach(b=>b.classList.remove('active'));document.querySelector('.plusTab').classList.add('active');document.getElementById('intakeTitle').textContent='Officer Override - Manual Case Mode';document.getElementById('editBanner').style.display='block';document.getElementById('editBanner').textContent='Manual override for '+c.id+'. Officer may change Reg E status, deadline settings, route, transactions, dates, and case parameters.';document.getElementById('caseSubmitBtn').textContent='Save Manual Override';document.getElementById('cancelEditBtn').style.display='inline-block';setManualControls(c);render()}
function commentAttachmentsHtml(files){if(!files||!files.length)return '';return '<div class="muted mini" style="margin-top:6px"><strong>Attachments:</strong><br>'+files.map(f=>'- '+f.name+' ('+Math.round((f.size||0)/1024)+' KB)').join('<br>')+'</div>'}
function getCommentAttachments(){let input=document.getElementById('commentFiles');if(!input||!input.files)return[];return Array.from(input.files).map(f=>({name:f.name,size:f.size,type:f.type||'unknown'}))}
function finderDatesHtml(c,calc){return '<h3>Case Timeline</h3><div class="notice">Simple date view: when the bank was told, when the case opened, when provisional credit is due, and the last day to finish the case.</div><table><tr><td>Notice Date</td><td>'+c.noticeDate+'</td></tr><tr><td>Opened Date</td><td>'+calc.openedDate+'</td></tr><tr><td>Provisional Credit Deadline</td><td>'+calc.provisionalCreditDate+' ('+calc.initialDays+' business days)</td></tr><tr><td>Final Case Deadline</td><td>'+calc.deadlineDate+' ('+calc.extendedDays+' calendar days, maximum allowed)</td></tr></table>'}
function caseParametersHtml(c,calc){return '<h3>Case Details</h3><table><tr><td>Reg E Status</td><td><strong>'+(calc.likelyRegE?'Reg E':'Non Reg E / Alternate Workflow')+'</strong></td></tr><tr><td>Manual Override</td><td>'+((c.manualRegEStatus&&c.manualRegEStatus!=='Auto')||c.manualRoute&&c.manualRoute!=='Auto'?'Yes':'No')+'</td></tr><tr><td>Manual Route</td><td>'+(c.manualRoute||'Auto')+'</td></tr><tr><td>Claim Type</td><td>'+c.claimType+'</td></tr><tr><td>Account</td><td>'+c.account+'</td></tr><tr><td>Total Claim Amount</td><td>'+money(c.amount)+'</td></tr><tr><td>Account Age</td><td>'+c.accountAge+'</td></tr><tr><td>Foreign / Outside U.S.</td><td>'+c.foreign+'</td></tr><tr><td>Access Device Status</td><td>'+c.deviceStatus+'</td></tr><tr><td>Prior Disputes Last 90 Days</td><td>'+c.prior+'</td></tr><tr><td>Risk Score</td><td>'+calc.score+'/100 - '+calc.level+'<div class="risk"><span style="width:'+calc.score+'%"></span></div></td></tr></table>'+finderDatesHtml(c,calc)+'<h3>Customer Statement</h3><div class="box">'+c.statement+'</div>'}

function hasCreditDecision(c){return !!(c.creditDecisionMade||c.provisional||c.creditRefused)}
function commonActionButtons(c){return '<button class="secondary" onclick="toggleAccountHistory()">Account History</button><button class="secondary" onclick="exportSelectedCaseJson()">Export Case JSON</button><button class="secondary" onclick="startEditCase()">Edit Case</button><button class="bad" onclick="deleteCase()">Delete Case</button>'}
function renderCaseActions(c){let bar=document.getElementById('caseActionBar');if(!bar)return;if(!c||c.auditReady){bar.innerHTML='';return}let html='';if(!c.officerDecision||c.status==='Officer Review Needed'){html='<button class="good" onclick="officerAgree()">Officer Agrees</button><button class="warn" onclick="officerOverride()">Officer Override</button>'}else if(!hasCreditDecision(c)&&!c.status.includes('Final')){html='<button class="primary" onclick="postCredit()">Give Provisional Credit</button>'+commonActionButtons(c)}else if(c.status==='Investigation Open'||c.status==='Needs Review'||c.status==='Ready for Credit Decision'){html='<button class="dark" onclick="markReadyFinal()">Review Finished</button>'+commonActionButtons(c)}else if(c.status==='Ready for Final Decision'){html='<button class="good" onclick="openFinalPermanentDecision()">Make Credit Permanent</button><button class="bad" onclick="openFinalRecoveryDecision()">Recover / Charge-Off Decision</button>'+commonActionButtons(c)}else if(c.status.includes('Final')){html='<button class="secondary" onclick="managerApprove()">Manager Sign-Off</button><button class="dark" onclick="markAuditReady()">Mark Audit Ready</button>'+commonActionButtons(c)}else{html=commonActionButtons(c)}bar.innerHTML=html}
function renderReview(){let c=cur();if(!c)return;if(c.auditReady&&activeView==='review'){document.getElementById('rTitle').textContent='Audit Ready Case Locked';document.getElementById('rSub').textContent='This case is complete and is only available in the Audit Log.';document.getElementById('workflowSteps').innerHTML='';renderCaseActions(c);document.getElementById('reviewBody').innerHTML='<div class="notice">Audit Ready cases are removed from the Review workflow. Open this case from the Audit Log to view details or use manager override editing.</div>';return}let calc=classify(c);let officerDone=!!c.officerDecision;document.getElementById('rTitle').textContent=c.id+' - '+c.customer;document.getElementById('rSub').textContent=c.source+' - '+c.txnType+' - '+c.claimType+' - '+money(c.amount);document.getElementById('workflowSteps').innerHTML=renderSteps(c);renderCaseActions(c);let leftPanel=officerDone?caseParametersHtml(c,calc):'<h3>Machine Recommendation</h3><table><tr><td>Likely Reg E?</td><td><strong>'+(calc.likelyRegE?'Yes':'No')+'</strong></td></tr><tr><td>Route</td><td>'+calc.route+'</td></tr><tr><td>Risk</td><td>'+calc.score+'/100 - '+calc.level+'<div class="risk"><span style="width:'+calc.score+'%"></span></div></td></tr><tr><td>Provisional credit deadline</td><td>'+calc.provisionalCreditDate+' ('+calc.initialDays+' business days)</td></tr><tr><td>Final case deadline</td><td>'+calc.deadlineDate+' ('+calc.extendedDays+' calendar days, maximum allowed)</td></tr><tr><td>Credit recommendation</td><td>'+calc.creditRecommendation+'</td></tr></table><div class="box">Reasoning:\n- '+calc.reason.join('\n- ')+'\n\nSuggested tasks:\n- '+calc.tasks.join('\n- ')+'</div>';let officerBox='<h3>Officer Decision</h3><table><tr><td>Decision</td><td>'+(c.officerDecision||'Pending officer agreement/override')+'</td></tr><tr><td>Comment</td><td>'+(c.officerComment||'None yet')+'</td></tr><tr><td>Investigation Status</td><td>'+c.status+'</td></tr><tr><td>Credit Status</td><td>'+c.creditStatus+'</td></tr><tr><td>Final Decision</td><td>'+(c.finalDecision||'Pending')+'</td></tr></table>'+flaggedTransactionsHtml(c);let rightPanel='<h3>Operational Parameters</h3><table><tr><td>Intake Source</td><td>'+c.source+'</td></tr><tr><td>Intake Officer</td><td>'+(c.intakeOfficer||'N/A')+'</td></tr><tr><td>Transaction Type</td><td>'+c.txnType+'</td></tr><tr><td>Manual Override</td><td>'+((c.manualRegEStatus&&c.manualRegEStatus!=='Auto')||c.manualRoute&&c.manualRoute!=='Auto'?'Yes':'No')+'</td></tr><tr><td>Manual Route</td><td>'+(c.manualRoute||'Auto')+'</td></tr><tr><td>Claim Type</td><td>'+c.claimType+'</td></tr><tr><td>Reg E / Non Reg E</td><td>'+(calc.likelyRegE?'Reg E':'Non Reg E')+'</td></tr><tr><td>Officer Override</td><td>'+(c.officerDecision&&c.officerDecision.includes('override')?'Manual override used':'No manual override')+'</td></tr><tr><td>Customer Statement</td><td>'+c.statement+'</td></tr><tr><td>Dates</td><td>Txn: '+c.txnDate+'<br>Notice: '+c.noticeDate+'<br>Opened: '+calc.openedDate+'<br>Provisional credit deadline: '+calc.provisionalCreditDate+'<br>Final case deadline: '+calc.deadlineDate+'</td></tr><tr><td>Extras</td><td>Account age: '+c.accountAge+'<br>Foreign: '+c.foreign+'<br>Device: '+c.deviceStatus+'<br>Prior disputes: '+c.prior+'</td></tr></table><h3>Comments</h3><div class="two"><input id="commentAuthor" placeholder="Officer name" value="S. Sanz"><input id="commentText" placeholder="Add case comment"></div><label>Attach files to comment</label><input id="commentFiles" type="file" multiple><button class="secondary" onclick="addComment()">Add Comment</button>'+(c.comments.map(cm=>'<div class="comment"><strong>'+cm.author+'</strong>'+cm.text+'<div class="muted mini">'+cm.time+'</div>'+commentAttachmentsHtml(cm.attachments)+'</div>').join('')||'<p class="muted">No comments yet.</p>');document.getElementById('reviewBody').innerHTML='<div class="two"><div>'+leftPanel+officerBox+'</div><div>'+rightPanel+'</div></div>'+'<hr class="divider"><h3>Audit Trail</h3>'+c.events.map(e=>'<div class="event">'+e.text+'<div class="muted mini">'+e.time+'</div></div>').join('')}

const CREDIT_BINS=['Fraud Loss Bin','Reg E Provisional Credit Bin','Zelle / P2P Claims Bin','ACH Claims Bin','Debit Card Claims Bin','ATM Claims Bin','FedNow / RTP Claims Bin','Operations Adjustment Bin','Credit Recovery / Reversal Bin'];
function defaultCreditBin(type){if(type==='Zelle / P2P')return 'Zelle / P2P Claims Bin';if(type==='ACH Debit')return 'ACH Claims Bin';if(type==='Debit Card POS')return 'Debit Card Claims Bin';if(type==='ATM Withdrawal')return 'ATM Claims Bin';if(type==='Online Banking Transfer')return 'Reg E Provisional Credit Bin';return 'Fraud Loss Bin'}
function binOptions(selected){return CREDIT_BINS.map(b=>'<option '+(b===selected?'selected':'')+'>'+b+'</option>').join('')}
function ledgerEntries(c){return c.provisionalLedger||[]}
function entryType(e){return (e.type||'').toLowerCase()}
function isChargeOffEntry(e){let t=entryType(e);return t.includes('charge-off')||t.includes('charge off')||t.includes('bank loss')}
function isRecoveryChargeOffEntry(e){let t=entryType(e);return t.includes('recovery charge-off')||t.includes('unrecovered provisional')}
function isPermanentEntry(e){let t=entryType(e);return t.includes('finalized customer credit')||t.includes('permanent customer credit')||t.includes('final customer credit')}
function isRecoveryEntry(e){let t=entryType(e);return (t.includes('customer recovery')||t.includes('recover')||t.includes('reversal'))&&!isPermanentEntry(e)&&!isChargeOffEntry(e)&&!t.includes('external recovery')}
function isExternalRecoveryEntry(e){let t=entryType(e);return t.includes('external recovery')}
function isPendingThirdPartyEntry(e){let t=entryType(e);return t.includes('pending third-party')||t.includes('pending third party')}
function isPositiveProvisionalEntry(e){let t=entryType(e);return Number(e.amount||0)>0&&!isChargeOffEntry(e)&&!isPermanentEntry(e)&&!isRecoveryEntry(e)&&!isExternalRecoveryEntry(e)&&!isPendingThirdPartyEntry(e)&&!t.includes('adjustment correction')}
function ledgerEntries(c){return c.provisionalLedger||[]}
function ledgerCreditTotal(c){return ledgerEntries(c).filter(isPositiveProvisionalEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerPermanentTotal(c){return ledgerEntries(c).filter(isPermanentEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerRecoveryTotal(c){return ledgerEntries(c).filter(isRecoveryEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerChargeOffTotal(c){return ledgerEntries(c).filter(isChargeOffEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerPendingThirdPartyTotal(c){return ledgerEntries(c).filter(isPendingThirdPartyEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerExternalRecoveryTotal(c){return ledgerEntries(c).filter(isExternalRecoveryEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerRecoveryChargeOffTotal(c){return ledgerEntries(c).filter(isRecoveryChargeOffEntry).reduce((a,e)=>a+Math.abs(Number(e.amount||0)),0)}
function ledgerActiveProvisional(c){return Math.max(ledgerCreditTotal(c)-ledgerPermanentTotal(c)-ledgerRecoveryTotal(c)-ledgerRecoveryChargeOffTotal(c),0)}
function ledgerTotal(c){return ledgerActiveProvisional(c)+ledgerPermanentTotal(c)+ledgerChargeOffTotal(c)+ledgerPendingThirdPartyTotal(c)-ledgerRecoveryTotal(c)-ledgerExternalRecoveryTotal(c)}

function provisionalBinSummary(c){
  let rows={};
  ledgerEntries(c).filter(isPositiveProvisionalEntry).forEach(e=>{
    let bin=e.bin||defaultCreditBin(caseTxnType(c));
    rows[bin]=(rows[bin]||0)+Number(e.amount||0);
  });
  return rows;
}
function provisionalBinSummaryHtml(c){
  let rows=provisionalBinSummary(c);
  let keys=Object.keys(rows);
  if(!keys.length)return '<p class="muted">No provisional credit source bin has been posted yet.</p>';
  return '<table><tr><th>Original Provisional Credit Bin</th><th>Amount Issued</th></tr>'+keys.map(k=>'<tr><td>'+k+'</td><td>'+money(rows[k])+'</td></tr>').join('')+'</table>';
}
function postPermanentLedgerUsingSelectedBin(c,amt,result,note,selectedBin,outcome){
  c.provisionalLedger=c.provisionalLedger||[];
  let amount=Math.abs(Number(amt||0));
  if(amount<=0)return;
  let todayStr=new Date().toISOString().slice(0,10);
  let bin=selectedBin||defaultCreditBin(caseTxnType(c));
  let outcomeText=outcome||'Charge off as bank loss';
  c.provisionalLedger.push({date:todayStr,type:'Finalized customer credit',transactionIndex:null,transaction:null,description:result+' - '+note+' Customer is allowed to keep this credit permanently.',amount:amount,bin:bin,officer:'Officer'});
  if(outcomeText==='Pending third-party recovery'){
    c.provisionalLedger.push({date:todayStr,type:'Pending third-party recovery',transactionIndex:null,transaction:null,description:'Permanent customer credit is expected to be recovered from merchant, network, ACH originator, receiving institution, insurer, or other third party.',amount:amount,bin:bin,officer:'Officer'});
    c.events.push(eventObj('Permanent credit posted with pending third-party recovery for '+money(amount)+'.'));
  }else if(outcomeText==='External recovery already received'){
    c.provisionalLedger.push({date:todayStr,type:'External recovery received',transactionIndex:null,transaction:null,description:'Permanent customer credit offset by external recovery already received.',amount:amount,bin:bin,officer:'Officer'});
    c.events.push(eventObj('Permanent credit posted and external recovery recorded for '+money(amount)+'.'));
  }else{
    c.provisionalLedger.push({date:todayStr,type:'Bank Loss / Charge-Off',transactionIndex:null,transaction:null,description:outcomeText+' - bank absorbs the finalized customer credit.',amount:amount,bin:bin,officer:'Officer'});
    c.events.push(eventObj('Permanent credit posted and bank loss / charge-off recognized for '+money(amount)+'.'));
  }
}

function postRecoveryLedgerEntry(c,reason,recoveredAmount,chargeOffAmount,recoveryBin,chargeOffBin){
  c.provisionalLedger=c.provisionalLedger||[];
  let todayStr=new Date().toISOString().slice(0,10);
  recoveredAmount=Math.abs(Number(recoveredAmount||0));
  chargeOffAmount=Math.abs(Number(chargeOffAmount||0));
  if(recoveredAmount>0){
    c.provisionalLedger.push({date:todayStr,type:'Customer Recovery / Reversal',transactionIndex:null,transaction:null,description:'Credit recovered or reversed from customer: '+reason,amount:recoveredAmount,bin:recoveryBin||'Credit Recovery / Reversal Bin',officer:'System/Officer'});
    c.events.push(eventObj('Customer recovery / reversal ledger entry posted for '+money(recoveredAmount)+'.'));
  }
  if(chargeOffAmount>0){
    c.provisionalLedger.push({date:todayStr,type:'Recovery Charge-Off / Unrecovered Provisional',transactionIndex:null,transaction:null,description:'Unrecovered provisional credit recognized as bank loss: '+reason,amount:chargeOffAmount,bin:chargeOffBin||'Fraud Loss Bin',officer:'System/Officer'});
    c.events.push(eventObj('Recovery charge-off ledger entry posted for '+money(chargeOffAmount)+'.'));
  }
}
function creditLedgerHtml(c){let entries=c.provisionalLedger||[];if(!entries.length)return '<h3>Credit Ledger</h3><p class="muted">No credit ledger entries yet.</p>';return '<h3>Credit Ledger</h3><table><tr><th>Date</th><th>Type</th><th>Description</th><th>Accounting Bin</th><th>Amount</th></tr>'+entries.map(e=>'<tr><td>'+e.date+'</td><td>'+e.type+'</td><td>'+e.description+'</td><td>'+e.bin+'</td><td>'+money(e.amount)+'</td></tr>').join('')+'<tr><td colspan="4"><strong>Active provisional credit</strong></td><td><strong>'+money(ledgerActiveProvisional(c))+'</strong></td></tr><tr><td colspan="4"><strong>Finalized customer credit</strong></td><td><strong>'+money(ledgerPermanentTotal(c))+'</strong></td></tr><tr><td colspan="4"><strong>Bank loss / charge-off</strong></td><td><strong>'+money(ledgerChargeOffTotal(c))+'</strong></td></tr><tr><td colspan="4"><strong>Pending third-party recovery</strong></td><td><strong>'+money(ledgerPendingThirdPartyTotal(c))+'</strong></td></tr><tr><td colspan="4"><strong>External recovery received</strong></td><td><strong>'+money(ledgerExternalRecoveryTotal(c))+'</strong></td></tr><tr><td colspan="4"><strong>Customer recovery / reversal</strong></td><td><strong>'+money(ledgerRecoveryTotal(c))+'</strong></td></tr></table>'}

function provisionalPostingHtml(c){
  let txns=getFlaggedTransactions(c);
  let rows=txns.map((t,i)=>'<tr><td><input type="checkbox" id="pcChk'+i+'" checked></td><td>'+t.date+'</td><td>'+t.type+'</td><td>'+t.merchant+'</td><td>'+money(t.amount)+'</td><td><input id="pcAmt'+i+'" type="number" step="0.01" value="'+Number(t.amount||0).toFixed(2)+'"></td><td><select id="pcBin'+i+'">'+binOptions(defaultCreditBin(t.type))+'</select></td></tr>').join('');
  return '<div class="notice">Select the disputed transactions that should receive provisional credit. You can also refuse provisional credit for this case if appropriate.</div><table style="margin-top:12px"><tr><th>Credit?</th><th>Date</th><th>Type</th><th>Merchant / Recipient</th><th>Claim Amount</th><th>Credit Amount</th><th>Funding Bin</th></tr>'+rows+'</table><h3>Optional Custom Credit</h3><div class="three"><div><label>Custom amount</label><input id="pcCustomAmount" type="number" step="0.01" value="0.00"></div><div><label>Custom funding bin</label><select id="pcCustomBin">'+binOptions(defaultCreditBin(caseTxnType(c)))+'</select></div><div><label>Officer</label><input id="pcOfficer" value="S. Sanz"></div></div><label>Posting note</label><textarea id="pcNote" rows="3">Provisional credit posted pending final investigation.</textarea><div class="row"><button class="good" onclick="submitProvisionalCredits()">Post Selected Credit</button><button class="bad" onclick="refuseProvisionalCredit()">Refuse Provisional Credit</button><button class="secondary" onclick="backToCaseReview()">Back to Case</button></div>';
}
function postCredit(){
  let c=cur();
  if(!c)return;
  if(!requireOfficer(c))return;
  if(hasCreditDecision(c)){alert('A provisional credit decision has already been made for this case. Use the Provisional Ledger adjustment workflow if a correction is needed.');return;}
  let total=transactionTotal(getFlaggedTransactions(c));
  if(total<200){
    c.provisionalLedger=c.provisionalLedger||[];
    c.provisionalLedger.push({date:new Date().toISOString().slice(0,10),type:'Provisional credit issued - low value loss',transactionIndex:null,transaction:null,description:'Automatic provisional credit under $200 threshold; reported to Fraud Loss Bin.',amount:total,bin:'Fraud Loss Bin',officer:'O.C.E.A.N Auto'});
    c.provisional=true;c.creditDecisionMade=true;c.creditRefused=false;c.creditStatus='Automatic provisional credit posted: '+money(total)+' from Fraud Loss Bin';
    c.events.push(eventObj('Automatic provisional credit posted for claim under $200: '+money(total)+'.'));
    c.comments.push(commentObj('O.C.E.A.N System','Automatic provisional credit was posted because the claim amount is under $200. The amount was reported to the Fraud Loss Bin.'));
    autoNotify(c,'Provisional credit notice generated and sent automatically by O.C.E.A.N.');
    render();return;
  }
  openCaseTool('Post Provisional Credit','Select the transactions and funding bins for provisional credit on '+c.id+'.',provisionalPostingHtml(c));
}
function submitProvisionalCredits(){
  let c=cur();if(!c)return;
  let txns=getFlaggedTransactions(c);let posted=0;let entries=0;let todayStr=new Date().toISOString().slice(0,10);let officer=(document.getElementById('pcOfficer')||{}).value||'Officer';let note=(document.getElementById('pcNote')||{}).value||'Provisional credit posted pending final investigation.';
  c.provisionalLedger=c.provisionalLedger||[];
  txns.forEach((t,i)=>{let chk=document.getElementById('pcChk'+i);if(chk&&chk.checked){let amt=Number((document.getElementById('pcAmt'+i)||{}).value||0);if(amt>0){let bin=(document.getElementById('pcBin'+i)||{}).value||defaultCreditBin(t.type);c.provisionalLedger.push({date:todayStr,type:'Provisional credit issued',transactionIndex:i,transaction:t,description:note,amount:amt,bin:bin,officer:officer});posted+=amt;entries++;}}});
  let custom=Number((document.getElementById('pcCustomAmount')||{}).value||0);if(custom>0){let bin=(document.getElementById('pcCustomBin')||{}).value||defaultCreditBin(caseTxnType(c));c.provisionalLedger.push({date:todayStr,type:'Custom provisional credit issued',transactionIndex:null,transaction:null,description:note,amount:custom,bin:bin,officer:officer});posted+=custom;entries++;}
  if(!entries){alert('Select at least one transaction or enter a custom amount, or use Refuse Provisional Credit.');return;}
  c.provisional=true;c.creditDecisionMade=true;c.creditRefused=false;c.creditStatus='Provisional credit posted: '+money(posted)+'; active exposure '+money(ledgerActiveProvisional(c));
  c.events.push(eventObj('Provisional credit posted: '+money(posted)+' across '+entries+' ledger entr'+(entries===1?'y':'ies')+'.'));
  c.comments.push(commentObj(officer,'Provisional credit posted. '+note));
  autoNotify(c,'Provisional credit letter generated and sent automatically by O.C.E.A.N.');
  save();render();backToCaseReview();
}
function refuseProvisionalCredit(){
  let c=cur();if(!c)return;
  let reason=prompt('Reason for refusing provisional credit:','Provisional credit refused based on case facts and current policy review.');
  if(reason===null)return;
  c.creditDecisionMade=true;c.creditRefused=true;c.provisional=false;c.creditStatus='Provisional credit refused';
  c.events.push(eventObj('Provisional credit refused. Reason: '+reason));
  c.comments.push(commentObj('Officer',reason));
  autoNotify(c,'Provisional credit decision notice generated automatically by O.C.E.A.N.');
  save();render();backToCaseReview();
}
function adjustmentHtml(c){
  return '<div class="notice">Use this to correct a provisional credit posting mistake. Adjustments are added as new ledger entries so the history stays intact.</div>'+creditLedgerHtml(c)+'<h3>Post Adjustment</h3><div class="three"><div><label>Adjustment amount</label><input id="adjAmount" type="number" step="0.01" value="0.00"></div><div><label>Funding / loss bin</label><select id="adjBin">'+binOptions(defaultCreditBin(caseTxnType(c)))+'</select></div><div><label>Officer</label><input id="adjOfficer" value="S. Sanz"></div></div><label>Adjustment reason</label><textarea id="adjReason" rows="3">Correction to provisional credit ledger.</textarea><div class="row"><button class="primary" onclick="submitProvisionalAdjustment()">Post Adjustment</button><button class="secondary" onclick="setTabByIndex(5,\'ledger\')">Back to Ledger</button><button class="secondary" onclick="selectCase(\''+c.id+'\')">Go to Case</button></div>';
}
function openProvisionalAdjustment(caseId){
  let c=cases.find(x=>x.id===caseId);if(!c)return;selectedId=c.id;openCaseTool('Provisional Credit Adjustment','Correct provisional credit activity for '+c.id+' - '+c.customer,adjustmentHtml(c));
}
function submitProvisionalAdjustment(){
  let c=cur();if(!c)return;let amt=Number((document.getElementById('adjAmount')||{}).value||0);if(!amt){alert('Enter a positive amount for additional credit or a negative amount for a reversal/correction.');return;}let bin=(document.getElementById('adjBin')||{}).value||defaultCreditBin(caseTxnType(c));let officer=(document.getElementById('adjOfficer')||{}).value||'Officer';let reason=(document.getElementById('adjReason')||{}).value||'Correction to provisional credit ledger.';c.provisionalLedger=c.provisionalLedger||[];c.provisionalLedger.push({date:new Date().toISOString().slice(0,10),type:amt<0?'Credit adjustment / reversal':'Credit adjustment / additional provisional credit',transactionIndex:null,transaction:null,description:reason,amount:amt,bin:bin,officer:officer});c.provisional=ledgerCreditTotal(c)>0;c.creditDecisionMade=true;c.creditStatus='Credit adjusted; active provisional exposure '+money(ledgerActiveProvisional(c));c.events.push(eventObj('Provisional credit adjustment posted: '+money(amt)+'. Reason: '+reason));c.comments.push(commentObj(officer,'Provisional credit adjustment posted: '+money(amt)+'. '+reason));autoNotify(c,'Customer credit correction notice generated automatically by O.C.E.A.N.');save();render();openProvisionalAdjustment(c.id);
}

function addToBinTotals(binTotals,bin,amount){bin=bin||'Unassigned Bin';binTotals[bin]=(binTotals[bin]||0)+Number(amount||0)}
function currentBinTotals(){let binTotals={};cases.forEach(c=>{let active=ledgerActiveProvisional(c);let provByBin=provisionalBinSummary(c);let provTotal=Object.values(provByBin).reduce((a,v)=>a+Number(v||0),0);if(active>0&&provTotal>0){Object.entries(provByBin).forEach(([bin,val])=>addToBinTotals(binTotals,bin,active*(Number(val||0)/provTotal)))}ledgerEntries(c).forEach(e=>{if(isPermanentEntry(e))addToBinTotals(binTotals,e.bin,Math.abs(Number(e.amount||0)));else if(isChargeOffEntry(e))addToBinTotals(binTotals,e.bin,Math.abs(Number(e.amount||0)));else if(isPendingThirdPartyEntry(e))addToBinTotals(binTotals,e.bin,Math.abs(Number(e.amount||0)));else if(isExternalRecoveryEntry(e))addToBinTotals(binTotals,e.bin,-Math.abs(Number(e.amount||0)));else if(isRecoveryEntry(e))addToBinTotals(binTotals,e.bin,-Math.abs(Number(e.amount||0)));});});return binTotals}
function renderLedger(){let el=document.getElementById('ledgerBody');if(!el)return;let totalClaimDebits=cases.reduce((a,c)=>a+transactionTotal(getFlaggedTransactions(c)),0);let grossProvisionalIssued=cases.reduce((a,c)=>a+ledgerCreditTotal(c),0);let activeExposure=cases.reduce((a,c)=>a+ledgerActiveProvisional(c),0);let finalizedCustomerCredit=cases.reduce((a,c)=>a+ledgerPermanentTotal(c),0);let customerRecovery=cases.reduce((a,c)=>a+ledgerRecoveryTotal(c),0);let chargedOff=cases.reduce((a,c)=>a+ledgerChargeOffTotal(c),0);let pendingThirdParty=cases.reduce((a,c)=>a+ledgerPendingThirdPartyTotal(c),0);let externalRecovery=cases.reduce((a,c)=>a+ledgerExternalRecoveryTotal(c),0);let uncreditedExposure=Math.max(totalClaimDebits-grossProvisionalIssued,0);let ledgerRows=[];cases.forEach(c=>(c.provisionalLedger||[]).forEach(e=>ledgerRows.push({caseId:c.id,customer:c.customer,account:c.account,claimTotal:transactionTotal(getFlaggedTransactions(c)),entry:e})));let historyRows=applySort(ledgerRows.filter(matchesLedgerRow),ledgerSort,(r,f)=>f==='caseId'?r.caseId:r.entry.date);let binTotals=currentBinTotals();let binHtml=Object.keys(binTotals).length?'<h3>Current Accounting Balance by Bin</h3><table><tr><th>Accounting Bin</th><th>Current Ledger Balance</th></tr>'+Object.entries(binTotals).map(([b,v])=>'<tr><td>'+b+'</td><td>'+money(v)+'</td></tr>').join('')+'</table>':'<p class="muted">No accounting-bin activity yet.</p>';el.innerHTML='<div class="four"><div class="card kpi"><span class="muted">Total Disputed Debit Exposure</span><strong>'+money(totalClaimDebits)+'</strong></div><div class="card kpi"><span class="muted">Active Provisional Credit</span><strong>'+money(activeExposure)+'</strong></div><div class="card kpi"><span class="muted">Finalized Customer Credit</span><strong>'+money(finalizedCustomerCredit)+'</strong></div><div class="card kpi"><span class="muted">Uncredited Dispute Exposure</span><strong>'+money(uncreditedExposure)+'</strong></div></div><div class="four"><div class="card kpi"><span class="muted">Bank Loss / Charge-Off</span><strong>'+money(chargedOff)+'</strong></div><div class="card kpi"><span class="muted">Pending Third-Party Recovery</span><strong>'+money(pendingThirdParty)+'</strong></div><div class="card kpi"><span class="muted">External Recovery Received</span><strong>'+money(externalRecovery)+'</strong></div><div class="card kpi"><span class="muted">Customer Recovery / Reversal</span><strong>'+money(customerRecovery)+'</strong></div></div>'+binHtml+'<h3>Ledger History</h3><table><tr><th>Date<button class="sortBtn" onclick="toggleLedgerSort(&quot;date&quot;)">'+sortArrow(ledgerSort,'date')+'</button></th><th>Case<button class="sortBtn" onclick="toggleLedgerSort(&quot;caseId&quot;)">'+sortArrow(ledgerSort,'caseId')+'</button><input class="filterInput" placeholder="Search case #" value="'+ledgerFilters.caseId+'" oninput="setLedgerFilter(&quot;caseId&quot;,this.value)"></th><th>Customer<input class="filterInput" placeholder="Search customer" value="'+ledgerFilters.customer+'" oninput="setLedgerFilter(&quot;customer&quot;,this.value)"></th><th>Account Number<input class="filterInput" placeholder="Search account" value="'+ledgerFilters.account+'" oninput="setLedgerFilter(&quot;account&quot;,this.value)"></th><th>Total Claim Debits</th><th>Ledger Type</th><th>Ledger Amount<input class="filterInput" placeholder="Search amount" value="'+ledgerFilters.amount+'" oninput="setLedgerFilter(&quot;amount&quot;,this.value)"></th><th>Accounting Bin</th><th>Action</th></tr>'+(historyRows.map(r=>'<tr><td>'+r.entry.date+'</td><td>'+r.caseId+'</td><td>'+r.customer+'</td><td>'+r.account+'</td><td>'+money(r.claimTotal)+'</td><td>'+r.entry.type+'</td><td>'+money(r.entry.amount)+'</td><td>'+r.entry.bin+'</td><td><button class="primary smallBtn" onclick="openProvisionalAdjustment(&quot;'+r.caseId+'&quot;)">Adjust Credit</button> <button class="secondary smallBtn" onclick="selectCase(&quot;'+r.caseId+'&quot;)">Go to Case</button></td></tr>').join('')||'<tr><td colspan="9">No ledger history rows match your filters.</td></tr>')+'</table>'}
function requireOfficer(c){if(!c.officerDecision){alert('Officer must agree with or override the machine recommendation before investigation actions.');return false}return true}function officerAgree(){let c=cur(),calc=classify(c);let note=prompt('Officer comment for agreement:','I agree with the machine recommendation: '+calc.route+'.');if(note===null)return;c.officerDecision='Agreed with machine';c.officerComment=note;c.status='Investigation Open';c.openedDate=c.openedDate||c.noticeDate;c.events.push(eventObj('Officer agreed with machine recommendation'));c.events.push(eventObj('Investigation started'));autoNotify(c,'Your claim is being reviewed by the disputes team.');render()}function officerOverride(){startManualOverride()}function markReadyFinal(){let c=cur();if(!requireOfficer(c))return;if(!hasCreditDecision(c)){alert('Make a provisional credit decision before finishing the review.');return}let note=prompt('Investigation review summary:','Evidence reviewed; ready for final decision.');if(!note)return;c.status='Ready for Final Decision';c.events.push(eventObj('Investigation review finished: '+note));c.comments.push(commentObj('Investigator',note));render()}function openFinalPermanentDecision(){let c=cur();if(!c)return;if(!requireOfficer(c))return;let outstanding=ledgerActiveProvisional(c)||ledgerCreditTotal(c)||transactionTotal(getFlaggedTransactions(c));openCaseTool('Final Decision - Customer Keeps Credit','Recognize customer credit permanently and move the case to manager review.',renderFinalPermanentPanel(c,outstanding))}
function renderFinalPermanentPanel(c,outstanding){return '<div class="notice">Use this when the customer keeps the credit. This converts active provisional credit into finalized customer credit, then records how the bank accounts for that finalized amount.</div><h3>Original Provisional Credit Source</h3>'+provisionalBinSummaryHtml(c)+'<div class="three" style="margin-top:12px"><div><label>Amount customer keeps permanently</label><input id="finalPermanentAmount" type="number" step="0.01" value="'+Number(outstanding||0).toFixed(2)+'"></div><div><label>Final accounting outcome</label><select id="finalAccountingOutcome"><option>Charge off as bank loss</option><option>Pending third-party recovery</option><option>External recovery already received</option><option>Operational / goodwill adjustment</option></select></div><div><label>Accounting bin</label><select id="finalPermanentBin">'+binOptions(defaultCreditBin(caseTxnType(c)))+'</select></div></div><div class="two"><div><label>Final result</label><select id="finalPermanentResult"><option>Error confirmed / customer reimbursed</option><option>Bank accepts loss below recovery threshold</option><option>Goodwill / operations adjustment</option><option>Expected third-party recovery</option></select></div><div><label>Active provisional to resolve</label><input readonly value="'+money(outstanding)+'"></div></div><label>Final decision note</label><textarea id="finalPermanentNote" rows="4">Final decision: customer keeps the credit permanently.</textarea><div class="row"><button class="good" onclick="submitFinalPermanentDecision()">Post Final Customer Credit Decision</button><button class="secondary" onclick="backToCaseReview()">Cancel</button></div>'}
function submitFinalPermanentDecision(){let c=cur();if(!c)return;let amt=Number(document.getElementById('finalPermanentAmount').value||0);if(amt<=0){alert('Enter the amount the customer keeps permanently.');return}let result=document.getElementById('finalPermanentResult').value;let bin=document.getElementById('finalPermanentBin').value||defaultCreditBin(caseTxnType(c));let outcome=document.getElementById('finalAccountingOutcome').value;let note=document.getElementById('finalPermanentNote').value||'Final decision: customer keeps credit permanently.';postPermanentLedgerUsingSelectedBin(c,amt,result,note,bin,outcome);c.finalDecision='Customer credited permanently';c.creditStatus='Finalized customer credit '+money(amt)+'; outcome: '+outcome+'; accounting bin: '+bin+'; active provisional credit '+money(ledgerActiveProvisional(c));c.status='Final Decision Made - Customer Credited';c.events.push(eventObj('Final decision posted: customer keeps '+money(amt)+' permanently. Accounting outcome: '+outcome+'. Bin: '+bin+'.'));
c.events.push(eventObj('Reg E control: report final results within 3 business days and correct confirmed error within 1 business day.'));c.events.push(eventObj('Case moved to manager review queue'));c.comments.push(commentObj('Final Decision',note+' Accounting outcome: '+outcome+'. Accounting bin: '+bin+'.'));autoNotify(c,'Final approval notice generated and sent; customer credit has been made permanent.');save();render();backToCaseReview()}

function openFinalRecoveryDecision(){let c=cur();if(!c)return;if(!requireOfficer(c))return;let outstanding=ledgerActiveProvisional(c)||ledgerCreditTotal(c);if(outstanding<=0){outstanding=transactionTotal(getFlaggedTransactions(c))}openCaseTool('Final Decision - Recovery / Charge-Off','Record how much provisional credit was recovered and how much must be charged off.',renderFinalRecoveryPanel(c,outstanding))}
function renderFinalRecoveryPanel(c,outstanding){return '<div class="notice">Use this when the investigation concludes the bank should recover the credit. If the full amount cannot be recovered, the remaining amount is recorded as a charge-off / bank loss.</div><table style="margin-top:12px"><tr><td>Outstanding provisional amount to resolve</td><td><strong>'+money(outstanding)+'</strong></td></tr></table><div class="three" style="margin-top:12px"><div><label>Recovery result</label><select id="finalRecoveryMode" onchange="syncRecoveryMode('+Number(outstanding||0).toFixed(2)+')"><option>Full amount recovered</option><option>Partial amount recovered</option><option>Nothing recovered</option></select></div><div><label>Amount recovered / reversed</label><input id="finalRecoveredAmount" type="number" step="0.01" value="'+Number(outstanding||0).toFixed(2)+'" oninput="calcChargeOff('+Number(outstanding||0).toFixed(2)+')"></div><div><label>Calculated charge-off</label><input id="finalChargeOffAmount" type="number" step="0.01" value="0.00" readonly></div></div><div class="two"><div><label>Recovery accounting bin</label><select id="finalRecoveryBin">'+binOptions('Credit Recovery / Reversal Bin')+'</select></div><div><label>Charge-off accounting bin</label><select id="finalChargeOffBin">'+binOptions('Fraud Loss Bin')+'</select></div></div><label>Final recovery / charge-off reason</label><textarea id="finalRecoveryNote" rows="4">No error found after investigation. Recovery and charge-off amounts recorded based on final collection outcome.</textarea><div class="row"><button class="bad" onclick="submitFinalRecoveryDecision('+Number(outstanding||0).toFixed(2)+')">Post Recovery / Charge-Off Decision</button><button class="secondary" onclick="backToCaseReview()">Cancel</button></div>'}
function syncRecoveryMode(outstanding){let mode=document.getElementById('finalRecoveryMode').value;let r=document.getElementById('finalRecoveredAmount');if(mode==='Full amount recovered')r.value=Number(outstanding||0).toFixed(2);if(mode==='Nothing recovered')r.value='0.00';calcChargeOff(outstanding)}
function calcChargeOff(outstanding){let recovered=Number(document.getElementById('finalRecoveredAmount').value||0);if(recovered<0)recovered=0;if(recovered>outstanding)recovered=outstanding;document.getElementById('finalRecoveredAmount').value=recovered.toFixed(2);document.getElementById('finalChargeOffAmount').value=Math.max(Number(outstanding||0)-recovered,0).toFixed(2)}
function submitFinalRecoveryDecision(outstanding){let c=cur();if(!c)return;let recovered=Number(document.getElementById('finalRecoveredAmount').value||0);if(recovered<0)recovered=0;if(recovered>outstanding)recovered=outstanding;let chargeOff=Math.max(Number(outstanding||0)-recovered,0);let note=document.getElementById('finalRecoveryNote').value||'No error found after investigation.';c.finalDecision='Recover / reverse credit';c.status='Final Decision Made - Recover Credit';postRecoveryLedgerEntry(c,note,recovered,chargeOff,document.getElementById('finalRecoveryBin').value,document.getElementById('finalChargeOffBin').value);c.creditStatus='Recovery posted '+money(recovered)+'; charge-off recognized '+money(chargeOff)+'; active provisional exposure '+money(ledgerActiveProvisional(c));c.events.push(eventObj('Final decision: recover/reverse credit. Recovered '+money(recovered)+'; charged off '+money(chargeOff)+'. Reason: '+note));c.events.push(eventObj('Reg E control: written explanation required; include right to request documents. If debiting provisional credit, notify date/amount and honor covered items for 5 business days.'));c.events.push(eventObj('Case moved to manager review queue'));c.comments.push(commentObj('Final Decision',note+' Recovered: '+money(recovered)+' Charge-off: '+money(chargeOff)));autoNotify(c,'Final denial/recovery notice generated and sent; recovery and charge-off amounts have been recorded in the ledger.');save();render();backToCaseReview()}
function managerApprove(){let c=cur();if(!c.status.includes('Final')){alert('Manager sign-off should occur after final decision.');return}let note=prompt('Manager review comment:','Manager reviewed final decision and audit trail.');if(note===null)return;c.managerReviewed=true;c.events.push(eventObj('Manager sign-off completed: '+note));c.comments.push(commentObj('Manager',note));render()}function markAuditReady(){let c=cur();if(!c.managerReviewed&&!confirm('Manager has not signed off. Mark audit ready anyway?'))return;c.auditReady=true;c.events.push(eventObj('Case marked audit ready'));c.events.push(eventObj('Reg E control: retain evidence of compliance for at least 2 years.'));selectedAuditId=c.id;selectedId=c.id;render();setTabByIndex(3,'audit')}function addComment(){let c=cur();let author=document.getElementById('commentAuthor').value||'Officer';let text=document.getElementById('commentText').value;let attachments=getCommentAttachments();if(!text&&!attachments.length){alert('Enter a comment or attach at least one file.');return}c.comments.push({...commentObj(author,text||'File attachment added'),attachments});c.events.push(eventObj('Comment added by '+author+(attachments.length?' with '+attachments.length+' attachment(s)':'')));render()}
function renderManager(){let rows=applySort(cases.filter(isManagerCase).filter(matchesManager),managerSort,(c,f)=>f==='caseId'?c.id:c.noticeDate);let bar=document.getElementById('managerFilterBar');if(bar){bar.innerHTML='<div class="three"><div><label>Case</label><input placeholder="Search case #" value="'+managerFilters.caseId+'" oninput="setManagerFilter(\'caseId\',this.value)"></div><div><label>Customer</label><input placeholder="Search customer" value="'+managerFilters.customer+'" oninput="setManagerFilter(\'customer\',this.value)"></div><div><label>Account</label><input placeholder="Search account" value="'+managerFilters.account+'" oninput="setManagerFilter(\'account\',this.value)"></div></div><div class="two"><div><label>Total Claim Amount</label><input placeholder="Search amount" value="'+managerFilters.amount+'" oninput="setManagerFilter(\'amount\',this.value)"></div><div><label>Status / Final Decision</label><input placeholder="Search status or decision" value="'+managerFilters.status+'" oninput="setManagerFilter(\'status\',this.value)"></div>'}document.getElementById('managerTable').innerHTML='<tr><th>Case<button class="sortBtn" onclick="toggleManagerSort(\'caseId\')">'+sortArrow(managerSort,'caseId')+'</button></th><th>Customer</th><th>Account</th><th>Total Claim Amount</th><th>Notice Date<button class="sortBtn" onclick="toggleManagerSort(\'noticeDate\')">'+sortArrow(managerSort,'noticeDate')+'</button></th><th>Status / Final Decision</th><th>Credit Status</th><th>Manager</th><th>Audit</th><th>Action</th></tr>'+(rows.map(c=>'<tr style="cursor:pointer" title="Open case" onclick="selectCase(\''+c.id+'\')"><td>'+c.id+'</td><td>'+c.customer+'</td><td>'+c.account+'</td><td>'+money(c.amount)+'</td><td>'+c.noticeDate+'</td><td>'+(c.finalDecision||c.status)+'</td><td>'+c.creditStatus+'</td><td>'+(c.managerReviewed?'Reviewed':'Pending')+'</td><td>'+(c.auditReady?'Ready':'Not ready')+'</td><td><button class="secondary smallBtn" onclick="event.stopPropagation();selectCase(\''+c.id+'\')">Open</button></td></tr>').join('')||'<tr><td colspan="10">No manager review cases match your filters.</td></tr>')}
function renderAudit(){let rows=applySort(cases.filter(isAuditCase).filter(matchesAudit),auditSort,(c,f)=>f==='caseId'?c.id:c.noticeDate);let table=document.getElementById('auditTable');if(!table)return;table.innerHTML='<tr><th>Case<button class="sortBtn" onclick="toggleAuditSort(\'caseId\')">'+sortArrow(auditSort,'caseId')+'</button><input class="filterInput" placeholder="Search case #" value="'+auditFilters.caseId+'" oninput="setAuditFilter(\'caseId\',this.value)"></th><th>Source<input class="filterInput" placeholder="Search source" value="'+auditFilters.source+'" oninput="setAuditFilter(\'source\',this.value)"></th><th>Customer<input class="filterInput" placeholder="Search customer" value="'+auditFilters.customer+'" oninput="setAuditFilter(\'customer\',this.value)"></th><th>Account Number<input class="filterInput" placeholder="Search account" value="'+auditFilters.account+'" oninput="setAuditFilter(\'account\',this.value)"></th><th>Case Type</th><th>Error Type</th><th>Status<input class="filterInput" placeholder="Search status" value="'+auditFilters.status+'" oninput="setAuditFilter(\'status\',this.value)"></th><th>Notice Date<button class="sortBtn" onclick="toggleAuditSort(\'noticeDate\')">'+sortArrow(auditSort,'noticeDate')+'</button></th><th>Action</th></tr>'+(rows.map(c=>{let calc=classify(c);return '<tr style="cursor:pointer" title="Open audit detail" onclick="openAuditCase(\''+c.id+'\')"><td>'+c.id+'</td><td>'+c.source+'</td><td>'+c.customer+'</td><td>'+c.account+'</td><td>'+caseTxnType(c)+'</td><td>'+caseClaimType(c)+'</td><td>'+badge(c)+'<div class="muted mini">'+(calc.likelyRegE?'Reg E':'Non Reg E')+'</div></td><td>'+c.noticeDate+'</td><td><button class="secondary smallBtn" onclick="event.stopPropagation();openAuditCase(\''+c.id+'\')">Open Audit</button></td></tr>'}).join('')||'<tr><td colspan="9">No audit cases match your search.</td></tr>')}
function renderAuditDetail(){let c=cases.find(x=>x.id===selectedAuditId);let el=document.getElementById('auditDetailFull')||document.getElementById('auditDetail');if(!el)return;if(!c){el.innerHTML='<div class="notice auditDetail">Select a case from the audit table or audit queue to view detailed logs.</div>';return}let calc=classify(c);el.innerHTML='<div class="between"><div><h3>Audit Detail: '+c.id+' - '+c.customer+'</h3><p class="muted">Account: '+c.account+' - '+c.source+' - '+(calc.likelyRegE?'Reg E':'Non Reg E')+' - Notice: '+c.noticeDate+'</p></div><div class="row"><button class="secondary" onclick="startEditCase()">Manager Edit / Override</button><button class="secondary" onclick="activeView=\'audit\';selectedAuditId=null;document.querySelectorAll(\'.view\').forEach(v=>v.classList.remove(\'active\'));document.getElementById(\'audit\').classList.add(\'active\');render()">Back to Audit List</button></div></div>'+finderDatesHtml(c,calc)+'<table><tr><td>Status</td><td>'+c.status+'</td></tr><tr><td>Final decision</td><td>'+(c.finalDecision||'Pending')+'</td></tr><tr><td>Credit status</td><td>'+c.creditStatus+'</td></tr><tr><td>Manager reviewed</td><td>'+(c.managerReviewed?'Yes':'No')+'</td></tr><tr><td>Audit ready</td><td>'+(c.auditReady?'Yes':'No')+'</td></tr></table>'+flaggedTransactionsHtml(c)+creditLedgerHtml(c)+'<h4>Events</h4>'+c.events.map(e=>'<div class="event">'+e.text+'<div class="muted mini">'+e.time+'</div></div>').join('')+'<h4>Comments</h4>'+(c.comments.map(cm=>'<div class="comment"><strong>'+cm.author+'</strong>'+cm.text+'<div class="muted mini">'+cm.time+'</div>'+commentAttachmentsHtml(cm.attachments)+'</div>').join('')||'<p class="muted">No comments.</p>')}
function resetNewCaseForm(){let c=document.getElementById('customer');if(c)c.value='New Demo Customer';let a=document.getElementById('account');if(a)a.value='111';let n=document.getElementById('noticeDate');if(n)n.value='2026-06-22';let st=document.getElementById('statement');if(st)st.value='Customer says they did not authorize this transaction.';renderTransactionRows([defaultTransaction()]);setManualControls(null);liveCalc();}
